DROP TABLE IF EXISTS driver_registry;
DROP TABLE IF EXISTS channel_registry;
DROP TABLE IF EXISTS store_registry;
DROP TABLE IF EXISTS hub_registry;
CREATE TABLE hub_registry (hub_ref TEXT PRIMARY KEY, hub_name TEXT, hub_city TEXT, hub_state TEXT, hub_latitude DOUBLE PRECISION, hub_longitude DOUBLE PRECISION);
CREATE TABLE store_registry (store_ref TEXT PRIMARY KEY, hub_ref TEXT, store_name TEXT, store_segment TEXT, store_plan_price DOUBLE PRECISION, location_note TEXT);
CREATE TABLE channel_registry (channel_ref TEXT PRIMARY KEY, channel_name TEXT, channel_type TEXT);
CREATE TABLE driver_registry (driver_ref TEXT PRIMARY KEY, driver_modal TEXT, driver_type TEXT);
